    font-weight:bold;
}
</style>
<div class="contenedor">
<h1>🏠 Aplicaciones de la Domótica</h1>
<p><strong>Instrucción:</strong> Selecciona la opción correcta para cada pregunta.</p>
<div class="pregunta">
<p><strong>1. ¿Para qué sirve el control de iluminación?</strong></p>
<input type="radio" name="p1" value="0" /> Abrir puertas automáticamente<br /><input type="radio" name="p1" value="1" /> Encender, apagar y regular luces<br /><input type="radio" name="p1" value="0" /> Regar plantas<br />
<div id="r1"></div>
</div>
<div class="pregunta">
<p><strong>2. ¿Qué función cumplen los sistemas de seguridad?</strong></p>
<input type="radio" name="p2" value="1" /> Vigilar y proteger el hogar<br /><input type="radio" name="p2" value="0" /> Ahorrar agua<br /><input type="radio" name="p2" value="0" /> Controlar la temperatura<br />
<div id="r2"></div>
</div>
<div class="pregunta">
<p><strong>3. ¿Qué hace el control de temperatura?</strong></p>
<input type="radio" name="p3" value="0" /> Encender televisores<br /><input type="radio" name="p3" value="1" /> Regular ventiladores y aire acondicionado<br /><input type="radio" name="p3" value="0" /> Abrir ventanas manualmente<br />
<div id="r3"></div>
</div>
<div class="pregunta">
<p><strong>4. ¿Cuál es el objetivo de la gestión energética?</strong></p>
<input type="radio" name="p4" value="0" /> Vigilar la casa<br /><input type="radio" name="p4" value="1" /> Optimizar el consumo eléctrico<br /><input type="radio" name="p4" value="0" /> Regar jardines<br />
<div id="r4"></div>
</div>
<div class="pregunta">
<p><strong>5. ¿Cómo funciona el riego inteligente?</strong></p>
<input type="radio" name="p5" value="0" /> Enciende luces automáticamente<br /><input type="radio" name="p5" value="0" /> Controla cámaras de seguridad<br /><input type="radio" name="p5" value="1" /> Riega según la humedad del suelo<br />
<div id="r5"></div>
</div>
<button onclick="calificar()">Calificar actividad</button>
<div id="resultadoFinal"></div>
</div>
<script>

function revisar(nombre,id,textoCorrecto){

let opciones=document.getElementsByName(nombre);
let seleccion=null;

for(let op of opciones){
    if(op.checked){
        seleccion=op.value;
    }
}

if(seleccion=="1"){
    document.getElementById(id).innerHTML=
    "<div class='correcto'>✔ Correcto. "+textoCorrecto+"</div>";
    return 1;
}
else{
    document.getElementById(id).innerHTML=
    "<div class='incorrecto'>✘ Incorrecto. "+textoCorrecto+"</div>";
    return 0;
}
}

function calificar(){

let puntos=0;

puntos+=revisar("p1","r1","El control de iluminación permite encender, apagar y regular la intensidad de las luces.");
puntos+=revisar("p2","r2","Los sistemas de seguridad utilizan cámaras, sensores y alarmas para proteger el hogar.");
puntos+=revisar("p3","r3","El control de temperatura regula ventiladores, calefacción o aire acondicionado.");
puntos+=revisar("p4","r4","La gestión energética monitorea y optimiza el consumo eléctrico.");
puntos+=revisar("p5","r5","El riego inteligente utiliza sensores de humedad para ahorrar agua.");

let nota=((puntos/5)*5).toFixed(1);

let mensaje="";

if(nota>=4.5){
    mensaje="🏆 Excelente desempeño";
}
else if(nota>=3){
    mensaje="👍 Buen trabajo";
}
else{
    mensaje="📚 Debes repasar el tema";
}

document.getElementById("resultadoFinal").innerHTML=
`
${mensaje}<br><br>
Respuestas correctas: ${puntos}/5<br>
Nota final: ${nota} / 5.0
`;
}

</script>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

