<script>
function calificar() {
  let total = 0;
  let respondidas = 0;
  for (let i = 1; i <= 5; i++) {
    const opciones = document.getElementsByName('p' + i);
    let respondida = false;
    for (const opcion of opciones) {
      const label = opcion.parentElement;
      label.classList.remove('correcta', 'incorrecta');
      if (opcion.checked) {
        respondida = true;
        respondidas++;
        if (opcion.value === '1') {
          total += 20;
          label.classList.add('correcta');
        } else {
          label.classList.add('incorrecta');
        }
      }
    }
    // Mostrar la correcta aunque no se haya elegido
    for (const opcion of opciones) {
      if (opcion.value === '1') {
        opcion.parentElement.classList.add('correcta');
      }
    }
  }

  const resultado = document.getElementById('resultado');
  const nombre = document.getElementById('nombreEstudiante').value.trim();

  if (nombre === "") {
    resultado.innerHTML = "⚠️ Por favor escribe tu nombre antes de calificar.";
    resultado.style.color = "#ffd54f";
    return;
  }

  if (respondidas < 5) {
    resultado.innerHTML = "⚠️ Por favor responde todas las preguntas antes de calificar.";
    resultado.style.color = "#ffd54f";
    return;
  }

  let mensaje = "";
  if (total === 100) mensaje = "🎉 ¡Excelente! Dominas los conceptos de domótica.";
  else if (total >= 60) mensaje = "👍 ¡Buen trabajo! Revisa los conceptos marcados en rojo.";
  else mensaje = "📚 Sigue practicando, repasa los conceptos de sensores y actuadores.";

  resultado.innerHTML = "👤 " + nombre + "<br>Tu calificación es: " + total + " / 100 <br>" + mensaje;
  resultado.style.color = "#00e5ff";
}
</script>
